mapper.select:
SELECT w.warehouse_code AS warehouseCode, w.warehouse_name AS warehouseName, m.materiel AS materialCode, m.materiel_desc AS materialName, SUM(CASE WHEN t.direction = 'IN' THEN t.qty ELSE 0 END) AS inboundQty, SUM(CASE WHEN t.direction = 'OUT' THEN t.qty ELSE 0 END) AS outboundQty, COALESCE(inv.qty, 0) AS balanceQty, MAX(t.operate_time) AS lastOperateTime FROM sp_warehouse_transaction t LEFT JOIN sp_warehouse w ON t.warehouse_id = w.id LEFT JOIN sp_materile m ON t.material_id = m.id LEFT JOIN ( SELECT warehouse_id, materiel_id, SUM(qty) qty FROM sp_inventory WHERE is_deleted = '0' GROUP BY warehouse_id, materiel_id ) inv ON inv.warehouse_id = t.warehouse_id AND inv.materiel_id = t.material_id WHERE 1 = 1
AND t.warehouse_id = #{req.warehouseId}
AND (m.materiel LIKE CONCAT('%', #{req.materialLike}, '%') OR m.materiel_desc LIKE CONCAT('%', #{req.materialLike}, '%'))
AND t.operate_time >= #{req.beginDate}
AND t.operate_time <= #{req.endDate}
GROUP BY t.warehouse_id, t.material_id, w.warehouse_code, w.warehouse_name, m.materiel, m.materiel_desc, inv.qty ORDER BY w.warehouse_code, m.materiel
